var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......늦었군.","JPN":"……遅かったな。","ENG":"You're late.","TWN":"……你們太慢了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장! 살아 있었구나?!","JPN":"隊長！　生きてたんだね！！","ENG":"Captain! You're alive!","TWN":"隊長！你還活著呀？！"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그러게 말했잖아. 우리도 살아 나왔는데 저 인간이 쉽게 죽을 리 없지.","JPN":"言っただろ。俺たちだって生き残ったのに、あの人がそう簡単に死ぬわけがない。","ENG":"I told you. If we made it out, there's no way he'd croak so easily.","TWN":"我就說吧，我們都逃出來了，他怎麼可能會那麼輕易死掉。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"다친 데는 어때.","JPN":"ケガの具合はどうだ？","ENG":"You okay?","TWN":"傷口怎麼樣？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"총알 몇 발 스친 정도야. 다행히 몸에 박힌 놈은 없는 거 같다.","JPN":"何発かかすった程度だ。幸い、貫通していない。","ENG":"Had a few bullets graze me. Fortunately none of them ended up inside me, I think.","TWN":"被子彈劃傷了幾處，沒有直接命中。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"괜찮은 거 맞아? 옷이 피투성인데?","JPN":"本当に大丈夫？　服が血まみれなんだけど。","ENG":"You sure you're okay? You're covered in blood!","TWN":"真的沒事嗎？你身上到處都是血痕。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"병원이라도 가봐야 하는 거 아냐?","JPN":"病院に行ったほうがいいんじゃない？","ENG":"Maybe you should go to the hospital.","TWN":"要不要去醫院看看？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"너 돌았냐? 우리 같은 놈들이 갈 병원이 어디 있어?","JPN":"お前、頭大丈夫か？　俺らみたいな人を受け入れてくれる病院がどこにあるんだよ。","ENG":"You serious? We can't go to the hospital.","TWN":"妳瘋了嗎？我們這種身份怎麼可能去醫院？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"아마 정문 넘어가자마자 경찰들에게 잡혀갈 텐데.","JPN":"入った途端に警察に連行されるだけだろ。","ENG":"The cops will cuff him right at the entrance.","TWN":"馬上會被員警們抓到的。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그래도......","JPN":"でも……","ENG":"Still...","TWN":"就算這樣……"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"지훈이 말이 맞아. 그리고 너무 걱정 마라.","JPN":"ゴトウの言うとおりだ。あと、そんなに心配する必要はない。","ENG":"Jihoon's right. And don't worry.","TWN":"智勳說的對，妳也不用太擔心。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이 정도는 파스나 좀 바르면 나으니까.","JPN":"この程度の傷は塗り薬で治る。","ENG":"I can just put a bandage on it. It should heal right up.","TWN":"這點小傷只要擦點藥就可以了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"내, 내가 발라 줄게.","JPN":"わ、私が塗ってあげる。","ENG":"L-let me help you with that.","TWN":"我、我來幫你吧。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"하이고, 여기가 네놈들 동창회 장소라도 되는 줄 아냐?","JPN":"まったく、ここをお前さんたちの憩い場と勘違いしてるんじゃないか？","ENG":"Come on, kids. This ain't some diner for your happy little reunion.","TWN":"哎喲，你們是在這裡開校友會嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"다 큰 놈들이 뭐 좋은 일로 왔다고 떠들어, 떠들긴.","JPN":"いい歳して祝い事でもないのに、そんなに賑やかにしやがって。","ENG":"Keep down the chatter, would ya? You're acting like a bunch of children.","TWN":"有什麼好事啊，這麼熱鬧。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"간판 안 보여? 여기 총포상이야, 총포상.","JPN":"看板が見えないのかい？　ここは銃砲屋だぞ、銃砲屋。","ENG":"Don't you see that sign? This place is a gun shop.","TWN":"沒看到招牌嗎？這裡是軍火店。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"카페에서 떠들려면 커피를 사고, 총포상에서 떠들려면 총을 사야 할 거 아냐.","JPN":"カフェでおしゃべりするならコーヒーを買え。銃砲屋でおしゃべりするなら銃を買え。","ENG":"Save your chitchat for a cafe or something. You ought to buy guns at a gun shop.","TWN":"想在咖啡店聊天就要點杯咖啡，想在軍火店聊天就必須買幾把槍。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"거 참 까탈스럽네, 영감.","JPN":"まあまあ、そんな冷たいこと言わないでくれよ、ジジイ。","ENG":"Don't be so grumpy.","TWN":"你可真苛刻，老頭。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"단골 손님 취급이 너무 야박한 거 아냐?","JPN":"常連客の扱いが雑すぎるんじゃないか？","ENG":"We're your best customers. Surely we deserve better treatment than this.","TWN":"你就這樣接待你們店的常客嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"단골 같은 소리 하네. 네놈들이 단골이면 거지떼도 귀빈이겠다.","JPN":"常連だと？　お前さんたちのことを常連と呼ぶなら、乞食が来てもVIP扱いしてやるさ。","ENG":"Best customers, my butt. If you're my best customers, the homeless guy across the street is VIP.","TWN":"如果你都算常客，那連那些乞討的流浪漢都能算是我的常客了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"그 동안 달아놓은 외상값이 대체 얼마인지 생각은 해본 적 있냐?","JPN":"これまでのツケを合わせたらいくらになるのか、考えたことはあんのか？","ENG":"Have you ever thought about how much you've already put on your tab?","TWN":"你還記得你在我們店賒的賬是多少錢嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"거, 좋은 일 하려다 보면 사정이 궁할 때도 있는 거지!","JPN":"まあまあ、人々のために働くんだから懐事情が多少悪い時だってあるのさ。","ENG":"Come on, sometimes doing the right thing isn't always so profitable!","TWN":"哎，行俠仗義的人難免會有點捉襟見肘的！"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"자기도 총포상 면허도 없는 주제에 너무 그러지 맙시다.","JPN":"そっちだって銃砲屋の営業許可なんてないんだし、あまり責めないでくれよ。","ENG":"Don't get picky with us when you're not even licensed to run this shop.","TWN":"你自己不是也沒有軍火店執照嗎。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"뭐가 어째 이놈아?!","JPN":"なんだと！？","ENG":"What did you say, you little brat?","TWN":"你這傢伙再說一遍？！"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그만해, 최지훈.","JPN":"よせ、ゴトウ。","ENG":"That's enough, Jihoon.","TWN":"夠了，崔智勳。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"미안하군, 내가 대신 사과하지.","JPN":"すまない。代わりに謝る。","ENG":"Sorry about that. I apologize on his behalf.","TWN":"我替他道歉，不好意思。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"솔직히 말해서 언제 외상값을 갚을 수 있을지 나도 잘 모르겠군.","JPN":"正直な話、いつツケが返せるかは何とも言えない。","ENG":"To be honest, I'm not sure when we'll be able to pay off the tab.","TWN":"說實話，我也不知道什麼時候能還清賒帳。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"우리 일은 댁이 더 잘 알 테니까.","JPN":"俺らの仕事についてはあんたもよく知っているだろ。","ENG":"You know about our line of business better than all of us.","TWN":"我們的情況你也懂。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 목숨이 붙어 있는 동안은 어떻게든 노력해 보도록 하지.","JPN":"だが、生きている限り、何とか頑張ってみるよ。","ENG":"But we'll keep trying, as long as we're alive.","TWN":"不過只要我們的命還在，一定會盡全力還。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그걸로 좀 참아 주시면 좋겠군.","JPN":"それでしばらく我慢してもらえると助かる。","ENG":"I hope that's enough to appease you for today.","TWN":"希望你諒解。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"......하여간 내가 전생에 무슨 죄를 지어서 저런 모지리들이랑 엮이게 됐는지 몰라.","JPN":"……ったく、ワシになんの罪があってこんなおバカ集団に構うことになっちまったんだ。","ENG":"I must have some crap-ass karma to have ended up doing business with a bunch of fools like you.","TWN":"……我到底造了什麼孽，跟你們這幫笨蛋扯上關係了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"알았으니까 빚 갚을 때까지 죽지 말고 목숨 간수나 잘 하라고.","JPN":"わかったから掛け金を返すまで死なずに、ちゃんと命だけは守れよ。","ENG":"Fine, then. Y'all better stay alive till you can pay me back.","TWN":"我知道啦，還完債前可千萬別死掉。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그런 의미에서 물건을 좀 더 가져갔으면 좋겠는데.","JPN":"そんなわけでまたいくつか貸してほしいんだが。","ENG":"Speaking of which, I was hoping to pick up some more gear.","TWN":"話說回來，其實我們是來拿點東西的。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"방금 그 난리를 떨었는데 외상을 더 달라고?","JPN":"また武器が欲しいと？　ワシがボランティアにでも見えるのか？","ENG":"Weren't we just talking about this? And you want to put more stuff on the tab?","TWN":"簡直亂來，你還要賒帳？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아까도 말했지만 우리 사정이 좀 그래서...... 지금은 죽어서 들어갈 관짝 살 돈도 없군.","JPN":"さっきも言ったが今は都合が悪いんだ……今すぐ死んだとして棺桶を買う金すらない。","ENG":"Like I said, we're not doing so great right now... We can't even afford our own coffins.","TWN":"我剛才也說過，我們手頭有些緊……身上連死後買棺材的錢也沒有了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"살아서 외상을 갚으려면 밑천이라도 좀 있어야 하지 않겠소?","JPN":"生きて掛け金を返すには、最低限の装備が必要だろう。","ENG":"We'll need something to keep us alive long enough to pay you back, after all.","TWN":"為了日後還債，總不能一點本錢也沒有吧？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"다음엔 꼭 가게에 소금을 사다 놔야겠어. 재수가 없으려니 원.","JPN":"明日からは店に塩を常備しておこう。入口に撒いてやらないとだ。","ENG":"Golly... I really should have walked around that ladder the other day.","TWN":"真夠倒楣，我下次一定要在門口撒些鹽。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"......알겠으니까 대충 골라 봐.","JPN":"……わかったから、適当に選んでいけ。","ENG":"Fine. Take your pick.","TWN":"……知道了，那就快挑吧。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"어, 정말?","JPN":"え、本当に？","ENG":"Err, really?","TWN":"啊，真的……？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"왠일이래, 저 짠돌이 영감이...... 진짜 죽을 날이 다 됐나?","JPN":"お、珍しいな。あのケチが……そろそろ終活か？","ENG":"What's gotten into this stingy old miser? Is he growing senile in his old age?","TWN":"那個吝嗇鬼老頭今天是怎麼了……是不是大限將至了呀？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"말하는 꼬라지 하고는...... 확 입을 꿰매어 버릴라.","JPN":"お前さんのその口は感謝の言葉も言えんのか？","ENG":"I'm still young enough to blow your yappy mouth off.","TWN":"你這臭嘴……看我把你的嘴巴縫上。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"도현이 그 놈, 너희들이 잡은 거지?","JPN":"リョウの件、お前さんたちだろ？","ENG":"You guys were the ones who took out that piece of scum Dohyun, weren't you?","TWN":"道賢是被你們抓的吧？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"벌써 소문이 퍼졌나 보군. 그런데?","JPN":"もう噂が広まったのか。それで？","ENG":"Word travels fast. What of it?","TWN":"消息傳得真快。是又如何？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"장민이와 호연이가 죽기 전에 말해둔 게 있어.","JPN":"サトウ夫婦から死ぬ前に頼まれたことがある。","ENG":"There's something that Jangmin and Hoyeon told me before they got whacked.","TWN":"張敏和浩然生前囑咐過我一件事。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"자기들 저축을 맡겨둘 테니까 혹시라도 그 석궁 양아치에게 당하게 되면 니들에게 전해 달라고.","JPN":"貯金を預けておくから、もし自分たちがあのボウガン野郎にやられたら、お前さんたちに渡してほしいと。","ENG":"They wanted me to pass on their savings to y'all if that crossbow-wielding maniac got to them.","TWN":"他們把存款都交給我了，說如果他們被殺害，就把存款轉交給你們。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"아, 아저씨랑 아줌마가?","JPN":"え、おじさんとおばさんが？","ENG":"Th-they did?","TWN":"啊，真的嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"젠장......","JPN":"ちくしょう……","ENG":"Darn it...","TWN":"該死……"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"그러니까 오늘은 맘대로 골라.","JPN":"だから、今日は値段は気にせず好きに選ぶといい。","ENG":"So feel free to choose to your liking today.","TWN":"所以今天就儘管挑吧。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"파격세일이다. 아무리 나라고 해도 죽은 놈 소원 정도는 들어 줘야지.","JPN":"特別セールだ。いくらワシでも死んだ者の遺言ぐらいは聞いてやらんと。","ENG":"I'll even give you a special discount. Even a miser like me has to respect the wishes of the dead.","TWN":"今天就全部破盤大特價啦！畢竟是死者的遺願。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......고맙군. 그럼 사양하지 않지.","JPN":"……助かる。では、遠慮せず。","ENG":"I appreciate that. I see no reason to turn down this offer.","TWN":"……謝謝，那就不客氣了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"혹시나 해서 물어보는 건데 니들 성냥팔이랑 싸울 생각이냐?","JPN":"念のために聞くが、お前さんたちはマッチ売りと戦うつもりか？","ENG":"If you don't mind me asking, are you kids really going to fight the Matchmaker?","TWN":"我說，你們是真的想要跟賣火柴組織廝殺嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"하여간 진짜, 죽으려면 뭔 짓을 못 해.","JPN":"ったく。死にたくてしょうがないみたいだな。","ENG":"Golly, you really have a death wish, don't you?","TWN":"哎，果然是一群不怕死的傢伙。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"창고에 폭탄이 대량으로 있으니까 그거나 좀 가져가.","JPN":"倉庫に爆弾が大量にあるから、好きなだけ持っていけ。","ENG":"Then you'd better take some explosives with you. I've got a bunch in storage.","TWN":"倉庫裡有不少炸彈，你們拿走吧。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"이번에 주문을 잘못 해서 재고가 많이 쌓였거든.","JPN":"今回、発注ミスで在庫が大量に余っているんだ。","ENG":"I made a mistake with the recent order, so there's plenty of surplus stock.","TWN":"訂貨的時候弄錯了數量，庫存積太多了。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"말해 두는데 성냥팔이 놈은 꽤 고등급 카운터야.","JPN":"言っとくが、マッチ売りの奴はかなり高ランクのカウンターだぞ。","ENG":"Just so you know, the Matchmaker's a pretty high-grade Counter.","TWN":"我提醒你們一句，賣火柴的是高等級制裁者。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"네놈들이 쓰는 저질 대인병기 정도로는 그 녀석 상대하기에 어림도 없어.","JPN":"お前さんたちが使う粗末な対人兵器じゃ、あいつ相手に歯が立たないだろう。","ENG":"Your crappy weapons designed to take out regular people won't even put a dent in that bastard.","TWN":"你們的劣質兵器對他造不成任何傷害。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"뭐, 그래 봐야 어차피 죽겠지만. 그래도 뭔가 통하는 무기는 들고 싸워 봐야지.","JPN":"まあ、どう足掻いたところでどうせ死ぬだろうがな。それでも少しは通じる武器で戦わないとな。","ENG":"Then again, I suppose you'll die either way... At the very least you could die trying with weapons that actually work.","TWN":"雖說用什麼武器都會是死路一條。但好歹也要死得氣派一些。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"아주 저주를 하세요, 영감님. 죽긴 누가 죽어.","JPN":"もはや呪いだぜ、ジジイ。俺らは死なないぞ。","ENG":"I'm starting to think you actually want us to die.","TWN":"你別烏鴉嘴了，老頭，你說誰死路一條。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......호의는 고맙게 받지.","JPN":"……ご好意はありがたく頂く。","ENG":"…Thank you for your favor.","TWN":"……謝謝你的好意。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"기왕 베푸는 김에 서비스도 하나 해 줬으면 좋겠군.","JPN":"せっかくだ、ついでにもう一つ頼みたいことがあるんだが。","ENG":"Since you're being so generous, I'd like to ask you for one more favor.","TWN":"不如你好人做到底，幫我們處理一個小問題如何？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"아주 내 간을 빼먹지 그러냐?","JPN":"老いぼれをこき使うのは程々にしろ。なんだ？","ENG":"You're really squeezing me dry here!","TWN":"你們這是要得寸進尺？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이 전화기 안에 뭐가 들어 있는지 확인 좀 해줄 수 있나?.","JPN":"この携帯の中に何が入ってるか調べてくれないか？","ENG":"Can you check what's in this phone?","TWN":"能幫我們看看這手機裡裝著什麼東西嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"어? 대장, 그건 도현이란 녀석이 가지고 있던 핸드폰이잖아?","JPN":"あれ？　隊長、それはリョウが持っていた携帯じゃない？","ENG":"Huh? Captain, isn't that Dohyun's phone?","TWN":"咦？隊長，那不是道賢那傢伙的手機嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그걸 왜 또 여기까지 가져 왔어?","JPN":"なんで持ってきたんだよ。","ENG":"Why did you bring it with you?","TWN":"你怎麼把那玩意帶來了？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"위치 추적이라도 당하면 어쩌려고?","JPN":"また追跡されたらどうするんだ？","ENG":"What if they track us down again?","TWN":"要是被跟蹤了怎麼辦？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"추적 장치는 아까 제거했다. 하지만 데이터 추출은 전문기술이 좀 필요하더군.","JPN":"追跡装置はさっき外した。しかし、データ抽出には専門技術が必要そうでな。","ENG":"I already removed the tracker. But I'll need someone with more expertise to extract the data.","TWN":"我已經刪除了定位系統，可惜提取資料還是需要專家幫忙才行。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"영감님이라면 할 수 있겠지?","JPN":"あんたならできるだろ？","ENG":"Can I count on you?","TWN":"老頭你應該能搞定吧？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"무기 말고 정보 팔아먹는 것도 댁의 부업 중 하나니까.","JPN":"武器だけじゃなく、情報を売るのもあんたの副業の一つなんだから。","ENG":"I know you've got a little side gig in selling information.","TWN":"除了武器，你平時不也靠販賣情報謀生嗎？"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"어휴...... 이 썩을 놈들.","JPN":"……はあ。しょうがねえな。","ENG":"Ugh... You rotten little...","TWN":"哎……該死的傢伙。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DEALER_NPC_MILITIA_NULL","text":{"KOREA":"알았으니까 기다려봐.","JPN":"わかったから待ってろ。","ENG":"Alright. Give me a minute.","TWN":"知道了，你等一下。"},"stage":{"bg":"WORKSHOP","bgm":"UI_BASE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};